let approvalContent = '(file not found)';
try {
  const buf = await this.helpers.getBinaryDataBuffer(items[0], 'data');
  approvalContent = buf.toString('utf-8');
} catch(e) {}

// Pending 항목 추출
const pendingRows = approvalContent
  .split('\n')
  .filter(l => l.trim().startsWith('|') && l.includes('Pending'))
  .join('\n');
const pendingSection = pendingRows || '(없음)';

const brief = [
  '---',
  'type: daily_brief',
  `date: ${dateStr}`,
  '---',
  `# Daily Brief - ${dateStr}`,
  '',
  '## Status',
  '```',
  statusOutput.trim(),
  '```',
  '',
  '## Approval Queue',
  pendingSection,
  '',
  "## Today's Focus",
  '- [ ] ',
  ''
].join('\n');

const fileName = `${dateCompact}_daily_brief.md`;
const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(brief, 'utf-8'),
  fileName,
  'text/markdown'
);

return [{ json: { dateCompact, fileName }, binary: { brief: binaryData } }];
